#include "biblia.h"

void Biblia::CarregarJudas(Biblia* b) {
    b->dados[JUDAS].nome = wxT("Judas");

    b->dados[JUDAS].capitulos[1].versos[1] = wxT("Judas, servo de Jesus Cristo, e irmão de Tiago, aos chamados, amados em Deus Pai, e guardados em Jesus Cristo:");
    b->dados[JUDAS].capitulos[1].versos[2] = wxT("Misericórdia, paz e amor vos sejam multiplicados.");
    b->dados[JUDAS].capitulos[1].versos[3] = wxT("Amados, enquanto eu empregava toda a diligência para escrever-vos acerca da salvação que nos é comum, senti a necessidade de vos escrever, exortando-vos a pelejar pela fé que de uma vez para sempre foi entregue aos santos.");
    b->dados[JUDAS].capitulos[1].versos[4] = wxT("Porque se introduziram furtivamente certos homens, que já desde há muito estavam destinados para este juízo, homens ímpios, que convertem em dissolução a graça de nosso Deus, e negam o nosso único Soberano e Senhor, Jesus Cristo.");
    b->dados[JUDAS].capitulos[1].versos[5] = wxT("Ora, quero lembrar-vos, se bem que já de uma vez para sempre soubestes tudo isto, que, havendo o Senhor salvo um povo, tirando-o da terra do Egito, destruiu depois os que não creram;");
    b->dados[JUDAS].capitulos[1].versos[6] = wxT("aos anjos que não guardaram o seu principado, mas deixaram a sua própria habitação, ele os tem reservado em prisões eternas na escuridão para o juízo do grande dia,");
    b->dados[JUDAS].capitulos[1].versos[7] = wxT("assim como Sodoma e Gomorra, e as cidades circunvizinhas, que, havendo-se prostituído como aqueles anjos, e ido após outra carne, foram postas como exemplo, sofrendo a pena do fogo eterno.");
    b->dados[JUDAS].capitulos[1].versos[8] = wxT("Contudo, semelhantemente também estes falsos mestres, sonhando, contaminam a sua carne, rejeitam toda autoridade e blasfemam das dignidades.");
    b->dados[JUDAS].capitulos[1].versos[9] = wxT("Mas quando o arcanjo Miguel, discutindo com o Diabo, disputava a respeito do corpo de Moisés, não ousou pronunciar contra ele juízo de maldição, mas disse: O Senhor te repreenda");
    b->dados[JUDAS].capitulos[1].versos[10] = wxT("Estes, porém, blasfemam de tudo o que não entendem; e, naquilo que compreendem de modo natural, como os seres irracionais, mesmo nisso se corrompem.");
    b->dados[JUDAS].capitulos[1].versos[11] = wxT("Ai deles! porque foram pelo caminho de Caim, e por amor do lucro se atiraram ao erro de Balaão, e pereceram na rebelião de Coré.");
    b->dados[JUDAS].capitulos[1].versos[12] = wxT("Estes são os escolhidos em vossos ágapes, quando se banqueteiam convosco, pastores que se apascentam a si mesmos sem temor; são nuvens sem água, levadas pelos ventos; são árvores sem folhas nem fruto, duas vezes mortas, desarraigadas;");
    b->dados[JUDAS].capitulos[1].versos[13] = wxT("ondas furiosas do mar, espumando as suas próprias torpezas, estrelas errantes, para as quais tem sido reservado para sempre o negrume das trevas.");
    b->dados[JUDAS].capitulos[1].versos[14] = wxT("Para estes também profetizou Enoque, o sétimo depois de Adão, dizendo: Eis que veio o Senhor com os seus milhares de santos,");
    b->dados[JUDAS].capitulos[1].versos[15] = wxT("para executar juízo sobre todos e convencer a todos os ímpios de todas as obras de impiedade, que impiamente cometeram, e de todas as duras palavras que ímpios pecadores contra ele proferiram.");
    b->dados[JUDAS].capitulos[1].versos[16] = wxT("Estes são murmuradores, queixosos, andando segundo as suas concupiscências; e a sua boca diz coisas muito arrogantes, adulando pessoas por causa do interesse.");
    b->dados[JUDAS].capitulos[1].versos[17] = wxT("Mas vós, amados, lembrai-vos das palavras que foram preditas pelos apóstolos de nosso Senhor Jesus Cristo;");
    b->dados[JUDAS].capitulos[1].versos[18] = wxT("os quais vos diziam: Nos últimos tempos haverá escarnecedores, andando segundo as suas ímpias concupiscências.");
    b->dados[JUDAS].capitulos[1].versos[19] = wxT("Estes são os que causam divisões; são sensuais, e não têm o Espírito.");
    b->dados[JUDAS].capitulos[1].versos[20] = wxT("Mas vós, amados, edificando-vos sobre a vossa santíssima fé, orando no Espírito Santo,");
    b->dados[JUDAS].capitulos[1].versos[21] = wxT("conservai-vos no amor de Deus, esperando a misericórdia de nosso Senhor Jesus Cristo para a vida eterna.");
    b->dados[JUDAS].capitulos[1].versos[22] = wxT("E apiedai-vos de alguns que estão na dúvida,");
    b->dados[JUDAS].capitulos[1].versos[23] = wxT("e salvai-os, arrebatando-os do fogo; e de outros tende misericórdia com temor, abominação até a túnica manchada pela carne.");
    b->dados[JUDAS].capitulos[1].versos[24] = wxT("Ora, àquele que é poderoso para vos guardar de tropeçar, e apresentar-vos ante a sua glória imaculados e jubilosos,");
    b->dados[JUDAS].capitulos[1].versos[25] = wxT("ao único Deus, nosso Salvador, por Jesus Cristo nosso Senhor, glória, majestade, domínio e poder, antes de todos os séculos, e agora, e para todo o sempre. Amém.");

}
